function decodeSsePayload(raw) {
  const text = String(raw || '').trim();
  if (!text) return null;
  try {
    return JSON.parse(Buffer.from(text, 'base64').toString('utf8'));
  } catch (_error) {
    return null;
  }
}

async function consumeSse(response) {
  if (!response.body) {
    throw new Error('missing_stream_body');
  }
  const reader = response.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let buffer = '';
  const events = [];
  let doneEvent = null;
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    let marker = buffer.indexOf('\n\n');
    while (marker >= 0) {
      const block = buffer.slice(0, marker);
      buffer = buffer.slice(marker + 2);
      const lines = block.split('\n');
      let eventName = '';
      let dataRaw = '';
      for (const line of lines) {
        if (line.startsWith('event: ')) {
          eventName = line.slice(7).trim();
        } else if (line.startsWith('data: ')) {
          dataRaw += line.slice(6).trim();
        }
      }
      if (eventName) {
        const payload = decodeSsePayload(dataRaw);
        events.push({ event: eventName, payload });
        if (eventName === 'done') {
          doneEvent = payload;
        }
      }
      marker = buffer.indexOf('\n\n');
    }
  }
  return { events, doneEvent };
}

function makeClient(baseUrl) {
  let cookie = '';
  return {
    async request(path, options = {}) {
      const headers = {
        ...(options.headers || {})
      };
      if (cookie) headers.Cookie = cookie;
      const response = await fetch(`${baseUrl}${path}`, {
        method: options.method || 'GET',
        headers,
        body: options.body
      });
      const setCookie = response.headers.get('set-cookie');
      if (setCookie) {
        cookie = setCookie.split(';')[0];
      }
      return response;
    },
    async json(path, options = {}) {
      const response = await this.request(path, options);
      const data = await response.json().catch(() => ({}));
      if (!response.ok) {
        const message = data && data.error ? data.error : `http_${response.status}`;
        throw new Error(message);
      }
      return data;
    }
  };
}

